async function runTool(name, args) {
  const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  const now   = new Date().toISOString();

  if (name === 'list_tasks') {
    const userFilter = isAdmin ? '' : '&assignee_id=eq.' + userId;
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/tasks?status=not.in.(done,cancelled)&deleted_at=is.null&organization_id=eq.' + orgId +
           userFilter + '&select=id,title,deadline,priority,status,assignee:users!tasks_assignee_id_fkey(full_name)' +
           '&order=deadline.asc.nullslast&limit=30',
      headers: sbHeaders
    });
  }

  if (name === 'create_task') {
    let assigneeId = userId;
    if (args.assignee_name && args.assignee_name.trim()) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) assigneeId = users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    return helpers.httpRequest({
      method: 'POST',
      url: sbUrl + '/rest/v1/tasks',
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify({
        title: args.title,
        deadline: args.deadline ?? null,
        priority: args.priority ?? 'medium',
        organization_id: orgId,
        assignee_id: assigneeId,
        created_by: userId,
        status: 'todo',
        source: 'whatsapp'
      })
    });
  }

  if (name === 'update_task') {
    let taskId = args.task_id;
    if (!taskId && args.task_title) {
      const found = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/tasks?organization_id=eq.' + orgId +
             '&title=ilike.' + encodeURIComponent(args.task_title.trim()) +
             '&deleted_at=is.null&select=id&limit=1',
        headers: sbHeaders
      });
      if (Array.isArray(found) && found.length > 0) taskId = found[0].id;
      else return { error: 'Task "' + args.task_title + '" not found.' };
    }
    if (!taskId) return { error: 'Provide task_id or task_title.' };

    const patch = {};
    if (args.status)   patch.status   = args.status;
    if (args.title)    patch.title    = args.title;
    if (args.deadline) patch.deadline = args.deadline;
    if (args.priority) patch.priority = args.priority;
    if (args.assignee_name) {
      const users = await helpers.httpRequest({
        method: 'GET',
        url: sbUrl + '/rest/v1/users?organization_id=eq.' + orgId +
             '&full_name=ilike.' + encodeURIComponent(args.assignee_name.trim() + '%') +
             '&select=id,full_name&limit=5',
        headers: sbHeaders
      });
      if (Array.isArray(users) && users.length > 0) patch.assignee_id = users[0].id;
      else return { error: 'User "' + args.assignee_name + '" not found in this organisation.' };
    }
    if (Object.keys(patch).length === 0) return { error: 'Nothing to update.' };

    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/tasks?id=eq.' + taskId + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
      body: JSON.stringify(patch)
    });
  }

  if (name === 'check_in') {
    return helpers.httpRequest({
      method: 'POST', url: sbUrl + '/rest/v1/rpc/attendance_check_in',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_user_id: userId, p_org_id: orgId })
    });
  }

  if (name === 'check_out') {
    return helpers.httpRequest({
      method: 'POST', url: sbUrl + '/rest/v1/rpc/attendance_check_out',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_user_id: userId, p_org_id: orgId })
    });
  }

  if (name === 'check_leave_balance') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_balances?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=remaining_days,entitled_days,used_days,leave_type:leave_types(name)',
      headers: sbHeaders
    });
  }

  if (name === 'apply_leave') {
    return helpers.httpRequest({
      method: 'POST', url: sbUrl + '/rest/v1/rpc/apply_leave_from_bot',
      headers: { ...sbHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        p_employee_id: userId, p_org_id: orgId,
        p_leave_type_id: args.leave_type_id,
        p_start_date: args.start_date, p_end_date: args.end_date,
        p_reason: args.reason ?? ''
      })
    });
  }

  if (name === 'list_leaves') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_requests?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&select=start_date,end_date,duration_days,status,reason,leave_type:leave_types(name)' +
           '&order=created_at.desc&limit=10',
      headers: sbHeaders
    });
  }

  if (name === 'daily_briefing') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/rpc/daily_briefing_for_bot?p_user_id=' + userId + '&p_org_id=' + orgId,
      headers: sbHeaders
    });
  }

  if (name === 'my_attendance') {
    const monthStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?employee_id=eq.' + userId +
           '&organization_id=eq.' + orgId +
           '&date=gte.' + monthStart +
           '&select=date,check_in_time,check_out_time,status&order=date.desc&limit=31',
      headers: sbHeaders
    });
  }

  if (name === 'team_attendance') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/attendance_records?organization_id=eq.' + orgId +
           '&date=eq.' + today + '&select=status,employee:users(full_name,role)',
      headers: sbHeaders
    });
  }

  if (name === 'list_pending_leaves') {
    return helpers.httpRequest({
      method: 'GET',
      url: sbUrl + '/rest/v1/leave_requests?status=eq.pending&organization_id=eq.' + orgId +
           '&select=id,employee:users!leave_requests_employee_id_fkey(full_name),' +
           'leave_type:leave_types(name),start_date,end_date,duration_days,reason' +
           '&order=created_at.asc',
      headers: sbHeaders
    });
  }

  if (name === 'approve_leave_request') {
    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/leave_requests?id=eq.' + args.leave_id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'approved', reviewed_by: userId, reviewed_at: now })
    });
  }

  if (name === 'reject_leave_request') {
    return helpers.httpRequest({
      method: 'PATCH',
      url: sbUrl + '/rest/v1/leave_requests?id=eq.' + args.leave_id + '&organization_id=eq.' + orgId,
      headers: { ...sbHeaders, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'rejected', reviewed_by: userId, reviewed_at: now, rejection_reason: args.rejection_reason })
    });
  }

  if (name === 'help') {
    const adminCmds = isAdmin ? [
      'team attendance', 'pending leaves', 'approve leave <id>', 'reject leave <id>'
    ] : [];
    return {
      commands: [
        'list my tasks','create a task','update task status',
        'check in','check out','my attendance',
        'leave balance','apply leave','list leaves','daily briefing',
        ...adminCmds
      ]
    };
  }

  return { error: 'Unknown tool: ' + name };
}

const history = JSON.parse(ctx.history || '[]');
const taskRules = '\n\n*Task rules:*\n- To REASSIGN or UPDATE an existing task → always use update_task (with task_title or task_id). NEVER call create_task for an existing task.\n- To create a BRAND NEW task → ask for title + assignee (who to assign to). Deadline and priority are optional. Once you have title and know the assignee (or confirmed it defaults to the current user), call create_task immediately. Do NOT show a JSON block or add an extra confirmation step.\n- If a previous message said a task was "not found", try update_task with task_title anyway before giving up.';
const roleNote = isAdmin
  ? '\n\nYou have *admin/manager* access:\n- list_tasks returns ALL org tasks (combined list, any member)\n- team_attendance shows today team status\n- list_pending_leaves shows leaves awaiting your review\n- approve_leave_request / reject_leave_request to act on them\n- create_task can assign to any team member'
  : '';

const messages = [
  { role: 'system', content: ctx.system_prompt + taskRules + roleNote },
  ...history,
  { role: 'user', content: ctx.message }
];

async function groqCall(msgs, toolChoice) {
  const keys = [groqKey, groqKey2, groqKey3].filter(Boolean);
  let lastErr;
  for (const k of keys) {
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + k, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'llama-3.3-70b-versatile',
          messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3
        })
      });
    } catch(e) {
      const code = String(e.message);
      if (code.includes('429') || code.includes('400')) { lastErr = e; continue; }
      throw e;
    }
  }
  throw lastErr;
}

async function llmCall(msgs, toolChoice) {
  try {
    return await groqCall(msgs, toolChoice);
  } catch(e) {
    if (orKey) {
      return await helpers.httpRequest({
        method: 'POST',
        url: 'https://openrouter.ai/api/v1/chat/completions',
        headers: { Authorization: 'Bearer ' + orKey, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://whatsapp-hrbot.vercel.app' },
        body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct', messages: msgs, tools, tool_choice: toolChoice || 'auto', max_tokens: 1024, temperature: 0.3 })
      });
    }
    throw e;
  }
}

let resp   = await llmCall(messages, isGreeting ? 'none' : 'auto');
let choice = resp.choices[0];
let iters  = 0;

while (!isGreeting && choice.finish_reason === 'tool_calls' && iters < 5) {
  const toolCalls = choice.message.tool_calls || [];
  messages.push(choice.message);
  for (const tc of toolCalls) {
    let toolResult;
    try { toolResult = await runTool(tc.function.name, JSON.parse(tc.function.arguments || '{}')); }
    catch(e) { toolResult = { error: e.message }; }
    messages.push({ role: 'tool', tool_call_id: tc.id, content: JSON.stringify(toolResult) });
  }
  resp   = await llmCall(messages);
  choice = resp.choices[0];
  iters++;
}

// Strip leaked tool-call JSON or trailing "Here's the task creation JSON:" blurbs
let output = (choice.message.content || '').trim();
output = output.replace(/\{[\s\S]*?"name"[\s\S]*?"parameters"[\s\S]*?\}\s*$/, '').trim();
output = output.replace(/here'?s the .*?json:?\s*$/i, '').trim();
return [{ json: { output } }];

const isGreeting = $('Build Context').item.json.is_greeting;
const aiOutput = $('AI Agent').item.json.output;

if (!isGreeting) {
  return [{ json: { output: aiOutput } }];
}

// Extract the pre-written greeting from the system prompt
const sp = $('Build Context').item.json.system_prompt;
const marker = 'Do NOT call any tools. Do NOT add anything:\n\n';
const idx = sp.indexOf(marker);
const greetText = idx >= 0
  ? sp.substring(idx + marker.length)
  : `Hello ${$('Build Context').item.json.user_name}! I am *HRBot*, your AI HR assistant.

*Here is what I can help you with:*
- *Tasks* - list, create, or update tasks
- *Attendance* - check in/out, view history
- *Leaves* - check balance, apply for leave
- *Daily briefing* - today's summary
- *Team attendance* - admin only

What would you like to do?`;

return [{ json: { output: greetText } }];
